-- ┌─────────────────────────────────────────────────────────┐
--   HELPERS
-- └─────────────────────────────────────────────────────────┘
local function tw(obj, t, style, dir, props)
    TS:Create(obj, TweenInfo.new(t, style or Enum.EasingStyle.Quad, dir or Enum.EasingDirection.Out), props):Play()
end

local function ni(class, parent, props)
    local o = Instance.new(class)
    for k,v in pairs(props or {}) do o[k] = v end
    o.Parent = parent
    return o
end

local function delay(t, fn) task.delay(t, fn) end

