local function createBtn(cfg)
    -- Container ngoài (bóng đổ giả)
    local shadow = ni("Frame", panel, {
        Size = UDim2.new(0, 186, 0, 106),
        AnchorPoint = Vector2.new(0.5, 0.5),
        Position = UDim2.new(cfg.posX, 0, 0.79, 4),
        BackgroundColor3 = C.Black,
        BackgroundTransparency = 1,
        BorderSizePixel = 0, ZIndex = 6,
    })
    ni("UICorner", shadow, { CornerRadius = UDim.new(0, 18) })

    -- Nút chính
    local btn = ni("TextButton", panel, {
        Size = UDim2.new(0, 182, 0, 102),
        AnchorPoint = Vector2.new(0.5, 0.5),
        Position = UDim2.new(cfg.posX, 0, 0.79, 0),
        BackgroundColor3 = cfg.bgColor,
        AutoButtonColor = false,
        Text = "",
        BackgroundTransparency = 1,
        BorderSizePixel = 0, ZIndex = 7,
    })
    ni("UICorner", btn, { CornerRadius = UDim.new(0, 16) })

    -- Gradient bên trong nút
    ni("UIGradient", btn, {
        Color = ColorSequence.new{
            ColorSequenceKeypoint.new(0, cfg.gradLight),
            ColorSequenceKeypoint.new(0.5, cfg.bgColor),
            ColorSequenceKeypoint.new(1, cfg.gradDark),
        },
        Rotation = 120,
    })

    -- Viền nút
    local stroke = ni("UIStroke", btn, {
        Color = cfg.strokeColor,
        Thickness = 2,
        Transparency = 1,
    })

    -- Shine ngang giữa nút
    local shine = ni("Frame", btn, {
        Size = UDim2.new(0.85, 0, 0, 1),
        AnchorPoint = Vector2.new(0.5, 0),
        Position = UDim2.new(0.5, 0, 0.42, 0),
        BackgroundColor3 = C.White,
        BackgroundTransparency = 0.75,
        BorderSizePixel = 0, ZIndex = 9,
    })
    ni("UICorner", shine, { CornerRadius = UDim.new(1,0) })
    ni("UIGradient", shine, {
        Transparency = NumberSequence.new{
            NumberSequenceKeypoint.new(0,   1),
            NumberSequenceKeypoint.new(0.3, 0.6),
            NumberSequenceKeypoint.new(0.7, 0.6),
            NumberSequenceKeypoint.new(1,   1),
        },
    })

    -- Glow vầng sáng
    local glow = ni("ImageLabel", btn, {
        Size = UDim2.new(2, 0, 2, 0),
        AnchorPoint = Vector2.new(0.5, 0.5),
        Position = UDim2.new(0.5, 0, 0.5, 0),
        BackgroundTransparency = 1,
        Image = "rbxassetid://5028857084",
        ImageColor3 = cfg.glowColor,
        ImageTransparency = 1, ZIndex = 6,
    })

    -- Cờ (flag)
    local flag = ni("TextLabel", btn, {
        Size = UDim2.new(1, 0, 0, 40),
        Position = UDim2.new(0, 0, 0, 6),
        BackgroundTransparency = 1,
        Text = cfg.flag,
        TextSize = 28,
        Font = Enum.Font.GothamBold,
        TextColor3 = C.White,
        TextTransparency = 1, ZIndex = 10,
    })

    -- Tên ngôn ngữ
    local label = ni("TextLabel", btn, {
        Size = UDim2.new(1, 0, 0, 20),
        Position = UDim2.new(0, 0, 0, 50),
        BackgroundTransparency = 1,
        Text = cfg.label,
        TextSize = 14,
        Font = Enum.Font.GothamBlack,
        TextColor3 = cfg.labelColor,
        TextTransparency = 1, ZIndex = 10,
    })
    ni("UIStroke", label, {
        Color = cfg.strokeColor,
        Thickness = 1,
        Transparency = 0.6,
    })

    -- Sub text
    local sub = ni("TextLabel", btn, {
        Size = UDim2.new(1, 0, 0, 14),
        Position = UDim2.new(0, 0, 0, 74),
        BackgroundTransparency = 1,
        Text = cfg.sublabel,
        TextSize = 9,
        Font = Enum.Font.Gotham,
        TextColor3 = C.TextMuted,
        TextTransparency = 1, ZIndex = 10,
    })

    -- Animate vào với delay stagger
    delay(cfg.delay, function()
        tw(shadow, 0.45, nil, nil, { BackgroundTransparency = 0.72 })
        tw(btn,    0.45, Enum.EasingStyle.Back, Enum.EasingDirection.Out, { BackgroundTransparency = 0 })
        tw(stroke, 0.45, nil, nil, { Transparency = 0.1 })
        tw(flag,   0.45, nil, nil, { TextTransparency = 0 })
        tw(label,  0.45, nil, nil, { TextTransparency = 0 })
        tw(sub,    0.45, nil, nil, { TextTransparency = 0 })
    end)

    -- ── Hover In
    btn.MouseEnter:Connect(function()
        tw(btn,    0.15, nil, nil, { Size = UDim2.new(0, 190, 0, 108), BackgroundColor3 = cfg.hoverColor })
        tw(stroke, 0.15, nil, nil, { Thickness = 2.8, Transparency = 0 })
        tw(glow,   0.20, nil, nil, { ImageTransparency = 0.58 })
        tw(shadow, 0.15, nil, nil, { BackgroundTransparency = 0.6 })
        tw(flag,   0.15, nil, nil, { TextSize = 30 })
        tw(label,  0.15, nil, nil, { TextColor3 = C.White })
    end)

    -- ── Hover Out
    btn.MouseLeave:Connect(function()
        tw(btn,    0.18, nil, nil, { Size = UDim2.new(0, 182, 0, 102), BackgroundColor3 = cfg.bgColor })
        tw(stroke, 0.18, nil, nil, { Thickness = 2, Transparency = 0.1 })
        tw(glow,   0.22, nil, nil, { ImageTransparency = 1 })
        tw(shadow, 0.18, nil, nil, { BackgroundTransparency = 0.72 })
        tw(flag,   0.18, nil, nil, { TextSize = 28 })
        tw(label,  0.18, nil, nil, { TextColor3 = cfg.labelColor })
    end)

    -- ── Click
    btn.MouseButton1Click:Connect(function()
        _G.Lang = cfg.lang

        -- Squeeze → bounce
        tw(btn, 0.07, Enum.EasingStyle.Quad, Enum.EasingDirection.In,  { Size = UDim2.new(0, 168, 0, 92) })
        tw(glow,0.08, nil, nil, { ImageTransparency = 0.35 })
        task.wait(0.08)
        tw(btn, 0.18, Enum.EasingStyle.Back, Enum.EasingDirection.Out, { Size = UDim2.new(0, 192, 0, 110) })
        task.wait(0.22)

        closeGui()

        -- Auto translate nếu chọn VN
        if _G.Lang == "VN" then
            task.spawn(function()
                local pgui = LocalPlayer:WaitForChild("PlayerGui")
                local dict = {
                    ["Players"] = "Người Chơi", ["Player"]   = "Người Chơi",
                    ["Chests"]  = "Rương",       ["Chest"]    = "Rương",
                    ["Fruits"]  = "Trái Ác Quỷ", ["Fruit"]    = "Trái Ác Quỷ",
                    ["Materials"]= "Nguyên Liệu",["Material"] = "Nguyên Liệu",
                    ["Quests"]  = "Nhiệm Vụ",    ["Quest"]    = "Nhiệm Vụ",
                    ["Swords"]  = "Kiếm",
                    ["Auto "]   = "Tự Động ",    ["Farm "]    = "Cày ",
                    ["Select "] = "Chọn ",        ["Buy "]     = "Mua ",
                    ["Weapon"]  = "Vũ Khí",       ["Level"]    = "Cấp",
                    ["Nearest"] = "Gần Nhất",
                }
                local function translateObj(obj)
                    if not (obj:IsA("TextLabel") or obj:IsA("TextButton")) then return end
                    local function apply()
                        local t = obj.Text
                        for en, vn in pairs(dict) do t = t:gsub(en, vn) end
                        if t ~= obj.Text then obj.Text = t end
                    end
                    apply()
                    obj:GetPropertyChangedSignal("Text"):Connect(apply)
                end
                for _, v in ipairs(pgui:GetDescendants()) do translateObj(v) end
                pgui.DescendantAdded:Connect(translateObj)
            end)
        end
    end)
end

