-- [3] RADAR CHỐNG LẠC TRÔI VÀ KẸT MAP RAID V2.0
-- ========================================================
pcall(function()
    local oldGetChildren
    oldGetChildren = hookfunction(workspace.Enemies.GetChildren, function(self)
        local enemies = oldGetChildren(self)
        local player = game.Players.LocalPlayer
        if not (player.Character and player.Character:FindFirstChild("HumanoidRootPart")) then return enemies end
        
        local ppos = player.Character.HumanoidRootPart.Position
        local validEnemies = {}
        
        local inRaid = false
        if ppos.Y > 2000 or (workspace:FindFirstChild("_WorldOrigin") and workspace._WorldOrigin:FindFirstChild("Locations")) then
            inRaid = true
        end
        
        for _, mob in ipairs(enemies) do
            if mob:FindFirstChild("HumanoidRootPart") then
                local dist = (mob.HumanoidRootPart.Position - ppos).Magnitude
                if inRaid then
                    if dist < 8000 then table.insert(validEnemies, mob) end
                else
                    table.insert(validEnemies, mob)
                end
            end
        end
        return validEnemies
    end)
end)
