spawn(function()
    local TweenService = game:GetService("TweenService")
    local Players = game:GetService("Players")
    
    while wait() do 
        if _G.SailBoat_Hydra then 
            pcall(function()
                local a = CheckBoat()
                local lp = Players.LocalPlayer
                
                if not a then 
                    -- 1. Nếu chưa có thuyền thì bay ra chỗ NPC Mua Thuyền
                    local npcPos = CFrame.new(-16927.451, 9.086, 433.864)
                    TeleportToTarget(npcPos)
                    if (npcPos.Position - lp.Character.HumanoidRootPart.Position).Magnitude <= 10 then 
                        game:GetService("ReplicatedStorage").Remotes.CommF_:InvokeServer("BuyBoat", _G.SelectedBoat)
                    end 
                    
                elseif a then 
                    -- 2. Nếu có thuyền rồi, kiểm tra xem nhân vật đã ngồi lái chưa
                    if lp.Character.Humanoid.Sit == false then 
                        local seatCFrame = a.VehicleSeat.CFrame * CFrame.new(0, 1, 0)
                        _tp(seatCFrame)
                        
                    else 
                        -- 3. NẾU ĐÃ NGỒI RỒI: Dùng TweenService để LƯỚT MƯỢT TỚI HYDRA ISLAND
                        local targetCFrame = CFrame.new(5433, 35, 290)
                        
                        -- Nếu gặp chướng ngại vật (boss/thuyền địch) thì bay thuyền lên cao né
                        if CheckEnemiesBoat() or CheckPirateGrandBrigade() or CheckTerrorShark() then 
                            targetCFrame = CFrame.new(5433, 150, 290)
                        end
                        
                        if a.PrimaryPart then
                            local distance = (a.PrimaryPart.Position - targetCFrame.Position).Magnitude
                            local speed = 270 -- Tốc độ bay thuyền (An toàn không bị giật lùi)
                            local timeToTravel = distance / speed
                            
                            local tweenInfo = TweenInfo.new(timeToTravel, Enum.EasingStyle.Linear)
                            local tween = TweenService:Create(a.PrimaryPart, tweenInfo, {CFrame = targetCFrame})
                            
                            tween:Play()
                            
