                                game:GetService("ReplicatedStorage").Remotes.CommF_:InvokeServer("BuyBoat", _G.SelectedBoat)
                            end
                            return
                        end

                        -- Nếu gặp Boss/Sự kiện biển -> Dừng thuyền, nhảy ra đánh
                        if (CheckShark() and _G.Shark) or (CheckTerrorShark() and _G.TerrorShark) or (CheckFishCrew() and _G.MobCrew) or (CheckPiranha() and _G.Piranha) or (CheckEnemiesBoat() and _G.FishBoat) or (CheckSeaBeast() and _G.SeaBeast1) or (_G.PGB and CheckPirateGrandBrigade()) or (_G.HCM and CheckHauntedCrew()) or (_G.Leviathan1 and CheckLeviathan()) then 
                            if char.Humanoid.Sit == true then char.Humanoid.Sit = false end
