                            for _, v in pairs(boat:GetDescendants()) do
                                if v:IsA("BasePart") then v.CanCollide = true end
                            end
                            return
                        end

                        local seat = boat:FindFirstChild("VehicleSeat")
                        if not seat then return end

                        -- Bắt nhân vật ngồi vào ghế lái
                        if char.Humanoid.Sit == false then 
                            local dist = (char.HumanoidRootPart.Position - seat.Position).Magnitude
                            if dist > 15 then 
                                _tp(seat.CFrame * CFrame.new(0, 3, 0)) 
                            else 
                                char.HumanoidRootPart.CFrame = seat.CFrame
                                seat:Sit(char.Humanoid)
                            end
                            return
                        end

