                        if char.Humanoid.Sit == true then 
                            local targetCFrame
                            if _G.DangerSc == "Lv 1" then targetCFrame = CFrame.new(-21998.375, 30, -682.309143)
                            elseif _G.DangerSc == "Lv 2" then targetCFrame = CFrame.new(-26779.5215, 30, -822.858032)
                            elseif _G.DangerSc == "Lv 3" then targetCFrame = CFrame.new(-31171.957, 30, -2256.93774)
                            elseif _G.DangerSc == "Lv 4" then targetCFrame = CFrame.new(-34054.6875, 30, -2560.12012)
                            elseif _G.DangerSc == "Lv 5" then targetCFrame = CFrame.new(-38887.5547, 30, -2162.99023)
                            elseif _G.DangerSc == "Lv 6" then targetCFrame = CFrame.new(-44541.7617, 30, -1244.8584)
                            elseif _G.DangerSc == "Lv Infinite" then targetCFrame = CFrame.new(-10000000, 31, 37016.25)
                            end
                            
                            if targetCFrame then
                                local boatPos = seat.Position
                                -- Khóa cao độ Y = 30 (Mặt nước chuẩn của Blox Fruits để ra Sea Event)
                                local flatTarget = Vector3.new(targetCFrame.X, 30, targetCFrame.Z)
                                local distance = (Vector3.new(boatPos.X, 0, boatPos.Z) - Vector3.new(flatTarget.X, 0, flatTarget.Z)).Magnitude
                                
                                if distance > 50 then
                                    -- Tắt va chạm và gỡ neo liên tục để đi xuyên bến cảng, xuyên đá
                                    for _, v in pairs(boat:GetDescendants()) do
                                        if v:IsA("BasePart") then 
