                                        end
                                    end

                                    -- Tốc độ: 4 stud mỗi khung hình (Khoảng 240 stud/giây -> Đủ nhanh và không văng)
                                    local speed = 4
                                    local moveDir = (flatTarget - Vector3.new(boatPos.X, 30, boatPos.Z)).Unit
                                    local newPos = Vector3.new(boatPos.X, 30, boatPos.Z) + (moveDir * speed)
                                    
                                    -- Dịch chuyển tịnh tiến toàn bộ thuyền
                                    boat:PivotTo(CFrame.lookAt(newPos, flatTarget))
                                else
                                    -- Tới nơi bật lại va chạm
                                    for _, v in pairs(boat:GetDescendants()) do
                                        if v:IsA("BasePart") then v.CanCollide = true end
                                    end
                                end
                            end
                        end
                    end)
