spawn(function()
    while wait() do 
        pcall(function()
            if _G.Raiding then 
                local player = game.Players.LocalPlayer
                local char = player.Character
                if player.PlayerGui.Main.TopHUDList.RaidTimer.Visible == true and char and char:FindFirstChild("HumanoidRootPart") then 
                    
                    local myPos = char.HumanoidRootPart.Position
                    
                    -- [1] TÌM CHÍNH XÁC ẢI CỦA MÌNH (Khóa radar 10.000 mét để không nhảy sang nhà hàng xóm)
                    local myIsland = nil
                    local highestNum = 0
                    for _, v in pairs(game:GetService("Workspace")._WorldOrigin.Locations:GetChildren()) do 
                        if string.find(v.Name, "Island") then 
                            local dist = (v.Position - myPos).Magnitude
                            if dist < 10000 then -- Lọc 100% đảo của thằng khác
                                local num = tonumber(string.match(v.Name, "%d+"))
                                if num and num > highestNum then 
                                    highestNum = num
                                    myIsland = v
                                end 
                            end 
                        end 
                    end
                    
                    -- [2] QUÉT QUÁI TRÊN ĐẢO VÀ ĐÁNH
                    local hasEnemy = false
                    for _, enemy in pairs(workspace.Enemies:GetChildren()) do 
                        if enemy:FindFirstChild("Humanoid") and enemy:FindFirstChild("HumanoidRootPart") and enemy.Humanoid.Health > 0 then 
                            hasEnemy = true
                            NextIs = false -- Khóa cái toggle qua ải cũ để nó không văng bậy
                            
                            -- Lao vào áp sát và đấm
                            W.Kill(enemy, _G.Raiding)
                            break 
                        end 
                    end
                    
                    -- [3] HẾT QUÁI THÌ QUA ẢI TIẾP THEO (Bay lên không trung chờ quái spawn)
                    if not hasEnemy and myIsland then
                        NextIs = false
                        local targetCFrame = myIsland.CFrame * CFrame.new(0, 60, 0)
                        if (myPos - targetCFrame.Position).Magnitude > 20 then
                            _tp(targetCFrame)
                        end
                    end
                else 
                    NextIs = false 
                end 
            else 
                NextIs = false 
            end 
