task.spawn(function()
    local o = require(game:GetService("ReplicatedStorage").Modules.Net)
    local w = require(game:GetService("ReplicatedStorage").Modules.CombatUtil)
    local hit = o:RemoteEvent("RegisterHit", true)
    local atk = game:GetService("ReplicatedStorage").Modules.Net["RE/RegisterAttack"]
    
    while task.wait(0.05) do 
        pcall(function()
            local char = game.Players.LocalPlayer.Character
            if char and char:FindFirstChild("HumanoidRootPart") then 
                local weapon = char:FindFirstChildOfClass("Tool")
                if weapon then 
                    local wName = w:GetWeaponName(weapon) 
                    local targets = {}
                    local primary = nil
                    
                    for _, mob in ipairs(workspace.Enemies:GetChildren()) do 
                        local root = mob:FindFirstChild("HumanoidRootPart")
                        local hum = mob:FindFirstChild("Humanoid")
                        
                        if root and hum and hum.Health > 0 and (root.Position - char.HumanoidRootPart.Position).Magnitude <= 60 then 
                            table.insert(targets, {mob, root})
                            if not primary then primary = root else
                                root.CFrame = primary.CFrame
                                root.CanCollide = false
                                root.Size = Vector3.new(60, 60, 60)
                                hum.WalkSpeed = 0
                                hum.JumpPower = 0
                            end
                        end 
                    end
                    
                    if #targets > 0 then 
                        local id = tostring(game.Players.LocalPlayer.UserId):sub(2,4) .. tostring(math.random(11111,99999))
                        atk:FireServer()
                        hit:FireServer(primary, targets, nil, nil, id)
                        for _, t in ipairs(targets) do 
                            w:ApplyDamageHighlight(t[1], char, wName, t[2])
                        end 
                    end 
                end 
            end 
        end)
    end 
end)
