task.spawn(function()
    local VirtualUser = game:GetService("VirtualUser")

    -- 1. HÀM CHỌN VŨ KHÍ MỚI
    _G.AttackSeaEvent = function()
        if _G.SeaEventWeapon == "Fruit M1" then 
            weaponSc("Blox Fruit")
            -- Bấm M1 (Chuột trái) liên tục
            VirtualUser:CaptureController()
            VirtualUser:ClickButton1(Vector2.new())
            -- Kèm theo xả skill
            Useskills("Blox Fruit","Z")
            Useskills("Blox Fruit","X")
            Useskills("Blox Fruit","C")
            Useskills("Blox Fruit","V")
        elseif _G.SeaEventWeapon == "Melee" then 
            weaponSc("Melee")
            VirtualUser:CaptureController()
            VirtualUser:ClickButton1(Vector2.new())
            Useskills("Melee","Z")
            Useskills("Melee","X")
            Useskills("Melee","C")
            task.wait(.1)
        end
    end

    -- 2. LOGIC TỌA ĐỘ VÀ NÉ CHIÊU TỪ NOX HUB
    local original_tp = _tp
    getgenv()._tp = function(targetCFrame)
        if not targetCFrame then return end
        
        -- Nox Hub: Sea Beast & Leviathan
        if _G.SeaBeast1 or _G.Leviathan1 then
            for _, sb in pairs(workspace.SeaBeasts:GetChildren()) do
                if sb:FindFirstChild("HumanoidRootPart") and sb:FindFirstChild("Health") and sb.Health.Value > 0 then
                    local dist = (targetCFrame.Position - sb.HumanoidRootPart.Position).Magnitude
                    if dist < 800 then 
                        targetCFrame = sb.HumanoidRootPart.CFrame * CFrame.new(math.random(-200, 300), 400, math.random(-200, 300))
                        break 
                    end
                end
            end
        end
        
        -- Nox Hub: Terror Shark giữ khoảng cách 60 stud né lốc
        if _G.TerrorShark then
            for _, ts in pairs(workspace.Enemies:GetChildren()) do
                if ts.Name == "Terrorshark" and ts:FindFirstChild("HumanoidRootPart") and ts.Humanoid.Health > 0 then
                    local dist = (targetCFrame.Position - ts.HumanoidRootPart.Position).Magnitude
                    if dist < 500 then 
                        targetCFrame = ts.HumanoidRootPart.CFrame * CFrame.new(0, 60, 0)
                        break 
                    end
                end
            end
        end
        
        return original_tp(targetCFrame)
    end
    
    -- 3. HÀM XẢ CHIÊU AUTO COMBAT
    local RunService = game:GetService("RunService")
    local attackTick = tick()
    RunService.Heartbeat:Connect(function()
        pcall(function()
            if tick() - attackTick < 0.2 then return end
            local lp = game.Players.LocalPlayer
            local char = lp.Character
            if not char or not char:FindFirstChild("HumanoidRootPart") then return end
            
            local currentTarget = nil
            local MousePosTarget = nil

            -- [ ƯU TIÊN 1: SEA BEAST / LEVIATHAN ]
            if _G.SeaBeast1 or _G.Leviathan1 then
                for _, sb in pairs(workspace.SeaBeasts:GetChildren()) do
                    if not sb:FindFirstChild("Health") or sb.Health.Value <= 0 then continue end
                    
                    local hrp = nil
                    if sb.Name == "SeaBeast1" and _G.SeaBeast1 then hrp = sb:FindFirstChild("HumanoidRootPart") end
                    if sb.Name == "Leviathan" and _G.Leviathan1 then hrp = sb:FindFirstChild("Leviathan Segment") end
                    
                    if hrp and (char.HumanoidRootPart.Position - hrp.Position).Magnitude < 800 then
                        currentTarget = hrp; MousePosTarget = hrp.Position; break
                    end
                end
            end

            -- [ ƯU TIÊN 2, 3, 4: ENEMIES FOLDER ]
            if not currentTarget and workspace:FindFirstChild("Enemies") then
                local overallCombat = _G.TerrorShark or _G.FishBoat or _G.PGB or _G.Shark or _G.Piranha or _G.MobCrew or _G.HCM
                if overallCombat then
                    for _, en in pairs(workspace.Enemies:GetChildren()) do
                        if not alive(en) then continue end

                        if en.Name == "Terrorshark" and _G.TerrorShark then
                            currentTarget = en:FindFirstChild("HumanoidRootPart")
                            if currentTarget then MousePosTarget = currentTarget.Position; break end
                        end

                        if en.Name == "FishBoat" and _G.FishBoat then
                             local targetBoat = en:FindFirstChild("Engine")
                             if targetBoat then currentTarget = targetBoat; MousePosTarget = targetBoat.Position; break end
                        elseif ((en.Name == "PirateBrigade" or en.Name == "PirateGrandBrigade") and _G.PGB) then
                             local targetBoat = en:FindFirstChild("Engine")
                             if targetBoat then currentTarget = targetBoat; MousePosTarget = targetBoat.Position; break end
                        end

                        local smallMobsFlags = { ["Shark"] = _G.Shark, ["Piranha"] = _G.Piranha, ["Fish Crew Member"] = _G.MobCrew, ["Haunted Crew Member"] = _G.HCM }
                        if smallMobsFlags[en.Name] and en:FindFirstChild("HumanoidRootPart") then
                            currentTarget = en:FindFirstChild("HumanoidRootPart")
                            if currentTarget then MousePosTarget = currentTarget.Position; break end
                        end
                    end
                end
            end
            
            -- Xả chiêu
            if currentTarget and MousePosTarget then
                MousePos = MousePosTarget
                attackTick = tick()
                _G.AttackSeaEvent()
            end
        end)
    end)
    
    -- 4. GIỮ NGUYÊN AUTO SAIL BOAT CỦA BANANA HUB
    local boatTick = tick()
    RunService.Heartbeat:Connect(function(deltaTime)
        pcall(function()
            if tick() - boatTick < 0.1 then return end
            boatTick = tick()
            local lp = game.Players.LocalPlayer
            local char = lp.Character
            if not char or not char:FindFirstChild("HumanoidRootPart") then return end

            if _G.SailBoats or _G.SailBoat_Hydra or _G.AutofindKitIs or _G.Prehis_Find then
                local boat = CheckBoat()
                if not boat then return end
                local seat = boat:FindFirstChild("VehicleSeat")
                if not seat then return end

                if char.Humanoid.Sit == true then 
                    local targetPos = nil
                    if _G.SailBoats then
                        if _G.DangerSc == "Lv 1" then targetPos = Vector3.new(-21998, 30, -682)
                        elseif _G.DangerSc == "Lv 2" then targetPos = Vector3.new(-26779, 30, -822)
                        elseif _G.DangerSc == "Lv 3" then targetPos = Vector3.new(-31171, 30, -2256)
                        elseif _G.DangerSc == "Lv 4" then targetPos = Vector3.new(-34054, 30, -2560)
                        elseif _G.DangerSc == "Lv 5" then targetPos = Vector3.new(-38887, 30, -2162)
                        elseif _G.DangerSc == "Lv 6" then targetPos = Vector3.new(-44541, 30, -1244)
                        elseif _G.DangerSc == "Lv Infinite" then targetPos = Vector3.new(-10000000, 30, 37016) end
                    elseif _G.AutofindKitIs then targetPos = Vector3.new(-10000000, 30, 37016)
                    elseif _G.Prehis_Find then targetPos = Vector3.new(-10000000, 30, 37016)
                    end
                    
                    if targetPos then
                        local flatTarget = Vector3.new(targetPos.X, 30, targetPos.Z)
                        if (Vector3.new(seat.Position.X, 0, seat.Position.Z) - Vector3.new(flatTarget.X, 0, flatTarget.Z)).Magnitude > 100 then
                            for _, v in pairs(boat:GetDescendants()) do if v:IsA("BasePart") then v.CanCollide = false; v.Anchored = false end end
                            local speed = 300 
                            local moveDir = (flatTarget - Vector3.new(seat.Position.X, 30, seat.Position.Z)).Unit
                            boat:PivotTo(CFrame.lookAt(Vector3.new(seat.Position.X, 30, seat.Position.Z) + (moveDir * (speed * deltaTime)), flatTarget))
                        end
                    end
                end
            else
                local boat = CheckBoat()
                if boat then for _, v in pairs(boat:GetDescendants()) do if v:IsA("BasePart") then v.CanCollide = true end end end
            end
        end)
    end)
end)
